```plantuml
@startuml
abstract class KindleNotes {
    <<abstract>>
    + title: String
    + author: String
    + notes: List<NoteElement>
    + parse()
}

class NoteElement {
    + section
    + heading
    + text
}

class KindleNotesHtml {
    <<KindleNotes>>
    - _html
    - _selector: Selector
    - _extract_notes()
}

class KindleNotesCsv {
    <<KindleNotes>>
    - _csv
    - _extract_notes()
}

class KindleNotesText {
    <<KindleNotes>>
    - _text
    - _extract_notes()
}

class KindleNotesHtml_1_21 {
    + selector
}

class KindleNotesHtml_1_23 {
    + selector
}

enum Selector {
    TITLE
    AUTHOR
    SECTIONS
    S_HEADING
    S_NOTE_HEADING
    S_NOTE_TEXT
}

class KindleNotesMarkdown {
    + convert(notes: KindleNotes)
}

class MarkdownFormatter {
    + TITLE
    + AUTHOR
    + SECTION
    + S_HEADING
    + S_TEXT
}

KindleNotes <|-- KindleNotesHtml
KindleNotes <|-- KindleNotesCsv
KindleNotes <|-- KindleNotesText
KindleNotesHtml <|-- KindleNotesHtml_1_21
KindleNotesHtml <|-- KindleNotesHtml_1_23
KindleNotesHtml --o Selector
KindleNotes o-- "n" NoteElement
KindleNotesMarkdown ..> MarkdownFormatter

@enduml
```
